In the project at "C:/Users/User/Downloads/SaaS X-Final-Rick-Test - Test Copie", I need to add a global search command palette (Ctrl+K) to App.tsx.

Add a CommandPalette component INSIDE App.tsx (before the AppContent component definition). This is a modal overlay that appears when pressing Ctrl+K.

Requirements:

1. Add state in AppContent: `const [isCommandPaletteOpen, setIsCommandPaletteOpen] = useState(false);`

2. Add useEffect for keyboard shortcut:
```tsx
useEffect(() => {
  const handleKeyDown = (e: KeyboardEvent) => {
    if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
      e.preventDefault();
      setIsCommandPaletteOpen(prev => !prev);
    }
    if (e.key === 'Escape') {
      setIsCommandPaletteOpen(false);
    }
  };
  document.addEventListener('keydown', handleKeyDown);
  return () => document.removeEventListener('keydown', handleKeyDown);
}, []);
```

3. Create a CommandPalette component (defined inside App.tsx or as a separate const before AppContent):

```tsx
const CommandPalette: React.FC<{ isOpen: boolean; onClose: () => void; onNavigate: (view: string) => void; }> = ({ isOpen, onClose, onNavigate }) => {
  const [query, setQuery] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 100);
      setQuery('');
    }
  }, [isOpen]);

  const commands = [
    { id: 'analyze', label: 'Nouvel Audit AEO', icon: '🔍', category: 'Navigation' },
    { id: 'dashboard', label: 'Dashboard Pro', icon: '📊', category: 'Navigation' },
    { id: 'projects', label: 'Monitoring AEO', icon: '📈', category: 'Navigation' },
    { id: 'generative-tools', label: 'Outils Génératifs', icon: '✨', category: 'Outils' },
    { id: 'smc-studio', label: 'SMC Studio', icon: '✏️', category: 'Outils' },
    { id: 'content-writer', label: 'AI Content Writer', icon: '📝', category: 'Outils' },
