    { id: 'robots-txt', label: 'Robots.txt Optimizer', icon: '🤖', category: 'Outils' },
    { id: 'bot-tracking', label: 'Suivi Bots IA', icon: '👁️', category: 'Outils' },
    { id: 'blog-optimizer', label: 'Blog Optimiser', icon: '📰', category: 'Outils' },
    { id: 'directory', label: 'Annuaire Indexé', icon: '📚', category: 'Navigation' },
    { id: 'recharge', label: 'GTO Gas Station', icon: '⛽', category: 'Navigation' },
    { id: 'clients', label: 'Base Clients', icon: '👥', category: 'Navigation' },
    { id: 'mission-orders', label: 'Ordres de Mission', icon: '📋', category: 'Navigation' },
    { id: 'alerts', label: 'Alertes AEO', icon: '🔔', category: 'Navigation' },
    { id: 'account', label: 'Compte & Plan', icon: '👤', category: 'Navigation' },
    { id: 'affiliation', label: 'Programme Partenaire', icon: '🤝', category: 'Navigation' },
  ];

  const filtered = query
    ? commands.filter(c => c.label.toLowerCase().includes(query.toLowerCase()))
    : commands;

  const grouped = filtered.reduce((acc, cmd) => {
    if (!acc[cmd.category]) acc[cmd.category] = [];
    acc[cmd.category].push(cmd);
    return acc;
  }, {} as Record<string, typeof commands>);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-start justify-center pt-[20vh]" onClick={onClose}>
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" />
      <div
        className="relative w-full max-w-[560px] bg-[#13131d] border border-white/[0.1] rounded-2xl shadow-2xl shadow-black/50 overflow-hidden animate-in fade-in zoom-in-95 duration-200"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Search Input */}
        <div className="flex items-center gap-3 px-5 py-4 border-b border-white/[0.08]">
          <Search size={18} className="text-gray-500 shrink-0" />
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Rechercher une page, un outil..."
            className="flex-1 bg-transparent text-white text-[15px] placeholder-gray-600 outline-none"
          />
          <kbd className="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">
            ESC
          </kbd>
        </div>

        {/* Results */}
        <div className="max-h-[340px] overflow-y-auto py-2 custom-scrollbar">
          {Object.keys(grouped).length === 0 ? (
            <div className="px-5 py-8 text-center text-gray-600 text-sm">Aucun résultat pour "{query}"</div>
          ) : (
            Object.entries(grouped).map(([category, cmds]) => (
              <div key={category}>
                <div className="px-5 py-2 text-[10px] font-bold text-gray-600 uppercase tracking-wider">{category}</div>
                {cmds.map((cmd) => (
                  <button
                    key={cmd.id}
                    onClick={() => { onNavigate(cmd.id); onClose(); }}
                    className="w-full flex items-center gap-3 px-5 py-2.5 text-left hover:bg-white/[0.04] transition-colors group"
                  >
                    <span className="text-base">{cmd.icon}</span>
                    <span className="text-[14px] text-gray-300 group-hover:text-white transition-colors">{cmd.label}</span>
                  </button>
                ))}
              </div>
            ))
          )}
        </div>

        {/* Footer */}
        <div className="px-5 py-3 border-t border-white/[0.06] flex items-center justify-between text-[11px] text-gray-600">
          <div className="flex items-center gap-3">
            <span className="flex items-center gap-1"><kbd className="px-1.5 py-0.5 bg-white/[0.04] border border-white/[0.08] rounded text-[10px] font-mono">↑↓</kbd> naviguer</span>
